# # # # # # # # # # # # # # # # # # # # # # #     """
# # # # # # # # # # # # # # # # # # # # # # #     FIX-T23-7: step_weight_alpha replaces curriculum.
# # # # # # # # # # # # # # # # # # # # # # #     alpha=1.0 at ep 0 ŌåÆ 0.0 at ep decay_epochs.
# # # # # # # # # # # # # # # # # # # # # # #     After decay_epochs: uniform AFCRPS weights.
# # # # # # # # # # # # # # # # # # # # # # #     """
# # # # # # # # # # # # # # # # # # # # # # #     if epoch >= decay_epochs:
# # # # # # # # # # # # # # # # # # # # # # #         return 0.0
# # # # # # # # # # # # # # # # # # # # # # #     return 1.0 - (epoch / decay_epochs)


