# # # # # # # # # # # # # # # # # # # # # #                 sr_loss = bd.get("short_range", 0.0)
# # # # # # # # # # # # # # # # # # # # # #                 elapsed = time.perf_counter() - t0
# # # # # # # # # # # # # # # # # # # # # #                 print(f"  [{epoch:>3}][{i:>3}/{len(train_loader)}]"
