# # # # # # # # # # # # # # # # # # # #             pred, _, all_trajs = model.sample(bl, num_ensemble=fast_ensemble,
# # # # # # # # # # # # # # # # # # # #                                               ddim_steps=ode_steps)
# # # # # # # # # # # # # # # # # # # #             T_active  = pred.shape[0]
