# # # # # # # # # # # # # # # # # # # #             dist = haversine_km_torch(denorm_torch(pred), denorm_torch(gt_sliced))
# # # # # # # # # # # # # # # # # # # #             acc.update(dist)

# # # # # # # # # # # # # # # # # # # #             a12, a24 = compute_sr_ade(model, bl, device)
# # # # # # # # # # # # # # # # # # # #             sr_12h_buf.append(a12)
# # # # # # # # # # # # # # # # # # # #             sr_24h_buf.append(a24)

# # # # # # # # # # # # # # # # # # # #             step_spreads = []
# # # # # # # # # # # # # # # # # # # #             for t in range(all_trajs.shape[1]):
