# # # # # # # # # # # # # # # # # # # #           f"[TARGET: <50 / <100 km]")
# # # # # # # # # # # # # # # # # # # #     print(f"{'='*64}\n")

# # # # # # # # # # # # # # # # # # # #     r["sr_12h"] = sr_12h
# # # # # # # # # # # # # # # # # # # #     r["sr_24h"] = sr_24h

