# # # # # # # # # # # # # # # # class SWAManager:
# # # # # # # # # # # # # # # #     def __init__(self, model, start_epoch=50):
# # # # # # # # # # # # # # # #         self.start_epoch = start_epoch
# # # # # # # # # # # # # # # #         self.n_averaged  = 0
# # # # # # # # # # # # # # # #         self.avg_state   = None

# # # # # # # # # # # # # # # #     def update(self, model, epoch):
# # # # # # # # # # # # # # # #         if epoch < self.start_epoch:
# # # # # # # # # # # # # # # #             return
# # # # # # # # # # # # # # # #         m  = _get_raw_model(model)
# # # # # # # # # # # # # # # #         sd = {k: v.detach().clone() for k, v in m.state_dict().items()
# # # # # # # # # # # # # # # #               if v.dtype.is_floating_point}
# # # # # # # # # # # # # # # #         if self.avg_state is None:
# # # # # # # # # # # # # # # #             self.avg_state = sd
# # # # # # # # # # # # # # # #             self.n_averaged = 1
# # # # # # # # # # # # # # # #         else:
# # # # # # # # # # # # # # # #             n = self.n_averaged
# # # # # # # # # # # # # # # #             for k in self.avg_state:
# # # # # # # # # # # # # # # #                 if k in sd:
# # # # # # # # # # # # # # # #                     self.avg_state[k].mul_(n / (n + 1)).add_(sd[k], alpha=1.0 / (n + 1))
# # # # # # # # # # # # # # # #             self.n_averaged += 1

# # # # # # # # # # # # # # # #     def apply_to(self, model):
# # # # # # # # # # # # # # # #         if self.avg_state is None:
# # # # # # # # # # # # # # # #             return None
# # # # # # # # # # # # # # # #         m  = _get_raw_model(model)
# # # # # # # # # # # # # # # #         sd = m.state_dict()
# # # # # # # # # # # # # # # #         backup = {k: sd[k].detach().clone() for k in self.avg_state if k in sd}
# # # # # # # # # # # # # # # #         for k, v in self.avg_state.items():
# # # # # # # # # # # # # # # #             if k in sd:
# # # # # # # # # # # # # # # #                 sd[k].copy_(v)
# # # # # # # # # # # # # # # #         return backup

# # # # # # # # # # # # # # # #     def restore(self, model, backup):
# # # # # # # # # # # # # # # #         if backup is None:
# # # # # # # # # # # # # # # #             return
# # # # # # # # # # # # # # # #         m  = _get_raw_model(model)
# # # # # # # # # # # # # # # #         sd = m.state_dict()
# # # # # # # # # # # # # # # #         for k, v in backup.items():
# # # # # # # # # # # # # # # #             if k in sd:
# # # # # # # # # # # # # # # #                 sd[k].copy_(v)


