# # # # # # # # # # # # # # #     if np.isfinite(ate) and ate < 79.94:  parts.append(f"ATEŌ£ģ{ate:.1f}")
# # # # # # # # # # # # # # #     if np.isfinite(cte) and cte < 93.58:  parts.append(f"CTEŌ£ģ{cte:.1f}")
# # # # # # # # # # # # # # #     if np.isfinite(h72) and h72 < 297.0:  parts.append(f"72hŌ£ģ{h72:.1f}")
