def _composite_score(r: dict) -> float:
    ade = r.get("ADE", float("inf"))
    h72 = r.get("72h", float("inf"))
    ate = r.get("ATE_mean", float("inf"))
    cte = r.get("CTE_mean", float("inf"))
    if not np.isfinite(ate): ate = ade * 0.46
    if not np.isfinite(cte): cte = ade * 0.53
    h12 = r.get("12h", float("inf"))
    h24 = r.get("24h", float("inf"))
    h48 = r.get("48h", float("inf"))
    return 100.0 * (
        0.05 * (ade / 136.0)
        + 0.10 * (h12 / 50.0)
        + 0.15 * (h24 / 100.0)
        + 0.20 * (h48 / 200.0)
        + 0.25 * (h72 / 300.0)
        + 0.13 * (ate / 80.0)
        + 0.12 * (cte / 94.0)
    )


def _beat_report(r: dict) -> str:
    parts = []
    for k, t in [("ADE", TARGETS["ADE"]), ("ATE_mean", TARGETS["ATE"]),
                  ("CTE_mean", TARGETS["CTE"]), ("72h", TARGETS["72h"]),
                  ("12h", TARGETS["12h"]), ("24h", TARGETS["24h"]),
                  ("48h", TARGETS["48h"])]:
        v = r.get(k, float("inf"))
        label = k.replace("_mean", "")
        if np.isfinite(v) and v < t:
            parts.append(f"{label}Ō£ģ{v:.1f}")
    return "­¤Åå BEAT: " + " ".join(parts) if parts else ""


def _gap_vs_sttrans(r: dict) -> str:
    parts = []
    for k, ref in [("ADE", TARGETS["ADE"]), ("72h", TARGETS["72h"]),
                    ("ATE_mean", TARGETS["ATE"]), ("CTE_mean", TARGETS["CTE"])]:
        v = r.get(k, float("nan"))
        label = k.replace("_mean", "")
        if np.isfinite(v):
            gap = v - ref
            arrow = "Ōåō" if gap < 0 else "Ōåæ"
            parts.append(f"{label}:{v:.0f}({arrow}{abs(gap):.0f})")
    return " | ".join(parts)


