def _norm_to_deg_local(arr: torch.Tensor) -> torch.Tensor:
    out = arr.clone()
    out[..., 0] = (arr[..., 0] * 50.0 + 1800.0) / 10.0
    out[..., 1] = (arr[..., 1] * 50.0) / 10.0
    return out


def _haversine_local(p1: torch.Tensor, p2: torch.Tensor) -> torch.Tensor:
    lat1 = torch.deg2rad(p1[..., 1]); lat2 = torch.deg2rad(p2[..., 1])
    dlat = lat2 - lat1; dlon = torch.deg2rad(p2[..., 0] - p1[..., 0])
    a = (torch.sin(dlat / 2).pow(2)
         + torch.cos(lat1) * torch.cos(lat2) * torch.sin(dlon / 2).pow(2))
    return 2.0 * R_EARTH * torch.asin(a.clamp(1e-12, 1 - 1e-12).sqrt())


def _compute_ate_cte_local(pred_deg, gt_deg):
    T = min(pred_deg.shape[0], gt_deg.shape[0])
    if T < 2:
        z = pred_deg.new_zeros(1, pred_deg.shape[1])
        return z, z
    lon1 = torch.deg2rad(gt_deg[:T-1, :, 0]); lat1 = torch.deg2rad(gt_deg[:T-1, :, 1])
    lon2 = torch.deg2rad(gt_deg[1:T, :, 0]);  lat2 = torch.deg2rad(gt_deg[1:T, :, 1])
    lon3 = torch.deg2rad(pred_deg[1:T, :, 0]);lat3 = torch.deg2rad(pred_deg[1:T, :, 1])
    y_along = torch.sin(lon2-lon1)*torch.cos(lat2)
    x_along = torch.cos(lat1)*torch.sin(lat2) - torch.sin(lat1)*torch.cos(lat2)*torch.cos(lon2-lon1)
    bear_along = torch.atan2(y_along, x_along)
    y_err = torch.sin(lon3-lon2)*torch.cos(lat3)
    x_err = torch.cos(lat2)*torch.sin(lat3) - torch.sin(lat2)*torch.cos(lat3)*torch.cos(lon3-lon2)
    bear_err = torch.atan2(y_err, x_err)
    total = _haversine_local(pred_deg[1:T], gt_deg[1:T])
    angle = bear_err - bear_along
    return total * torch.cos(angle), total * torch.sin(angle)


