#  Per-storm evaluation
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

_HORIZON_STEPS = {12: 1, 24: 3, 48: 7, 72: 11}


class PerStormAccumulator:
    def __init__(self):
        self.data = defaultdict(lambda: {
            "dists": [], "ates": [], "ctes": [],
            "step_dists": defaultdict(list), "n_seq": 0})

    def update(self, sid, dist, ate, cte):
        d = self.data[sid]
        d["dists"].extend(dist.mean(0).tolist())
        d["n_seq"] += dist.shape[1]
        for h, s in _HORIZON_STEPS.items():
            if s < dist.shape[0]:
                d["step_dists"][h].extend(dist[s].tolist())
        if ate is not None: d["ates"].extend(ate.abs().mean(0).tolist())
        if cte is not None: d["ctes"].extend(cte.abs().mean(0).tolist())

    def compute(self, sid) -> dict:
        d = self.data[sid]
        r = {"storm_id": sid, "n_seq": d["n_seq"],
             "ADE": float(np.mean(d["dists"])) if d["dists"] else float("nan"),
             "ATE": float(np.mean(d["ates"]))  if d["ates"]  else float("nan"),
             "CTE": float(np.mean(d["ctes"]))  if d["ctes"]  else float("nan")}
        for h in _HORIZON_STEPS:
            vals = d["step_dists"].get(h, [])
            r[f"{h}h"] = float(np.mean(vals)) if vals else float("nan")
        return r

    def compute_overall(self) -> dict:
        all_d, all_a, all_c = [], [], []
        step_all = defaultdict(list); n = 0
        for d in self.data.values():
            all_d.extend(d["dists"]); all_a.extend(d["ates"])
            all_c.extend(d["ctes"]); n += d["n_seq"]
            for h, vals in d["step_dists"].items():
                step_all[h].extend(vals)
        r = {"storm_id": "OVERALL", "n_seq": n,
             "ADE": float(np.mean(all_d)) if all_d else float("nan"),
             "ATE": float(np.mean(all_a)) if all_a else float("nan"),
             "CTE": float(np.mean(all_c)) if all_c else float("nan")}
        for h in _HORIZON_STEPS:
            vals = step_all.get(h, [])
            r[f"{h}h"] = float(np.mean(vals)) if vals else float("nan")
        return r


def _extract_storm_ids(batch) -> Optional[List[str]]:
    for idx in [2, 12, 14, 15]:
        if idx < len(batch):
            item = batch[idx]
            if isinstance(item, (list, tuple)) and item and isinstance(item[0], str):
                return list(item)
            if torch.is_tensor(item) and item.dtype == torch.long:
                return [str(x.item()) for x in item]
    return None


@torch.no_grad()
def evaluate_per_storm(model, loader, device, args,
                        ema_obj=None) -> List[dict]:
    backup = None
    if ema_obj is not None:
        try: backup = ema_obj.apply_to(model)
        except: pass

    model.eval()
    acc = PerStormAccumulator()

    for batch in loader:
        bl  = move(list(batch), device)
        sids = _extract_storm_ids(batch)
        pred, _, _ = model.sample(bl, num_ensemble=1, ddim_steps=1)
        gt   = bl[1]
        T    = min(pred.shape[0], gt.shape[0])
        B    = pred.shape[1]
        pd   = _norm_to_deg_local(pred[:T])
        gd   = _norm_to_deg_local(gt[:T])
        dist = _haversine_local(pd, gd)
        ate, cte = _compute_ate_cte_local(pd, gd)

        if sids and len(sids) == B:
            for b in range(B):
                acc.update(sids[b], dist[:, b:b+1],
                            ate[:, b:b+1] if ate is not None else None,
                            cte[:, b:b+1] if cte is not None else None)
        else:
            acc.update("STORM_ALL", dist, ate, cte)

    if backup is not None:
        try: ema_obj.restore(model, backup)
        except: pass

    storms = sorted(s for s in acc.data if s != "STORM_ALL")
    if not storms: storms = ["STORM_ALL"]
    results = [acc.compute(s) for s in storms]
    results.append(acc.compute_overall())
    return results


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
