# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

def _eval_batch(pred_norm, gt_norm):
    pred_d = denorm_torch(pred_norm)
    gt_d   = denorm_torch(gt_norm)
    if HAS_ATECTE:
        dist, ate, cte = haversine_and_atecte_torch(
            pred_d, gt_d, unit_01deg=True)
        return dist, ate, cte
    return haversine_km_torch(pred_d, gt_d), None, None


def evaluate_fast(model, loader, device, pred_len: int) -> dict:
    model.eval()
    acc = StepErrorAccumulator(pred_len)
    t0 = time.perf_counter(); n = 0
    with torch.no_grad():
        for batch in loader:
            bl   = move(list(batch), device)
            pred, _, _ = model.sample(bl, num_ensemble=1, ddim_steps=1)
            gt   = bl[1][:pred.shape[0]]
            dist, ate, cte = _eval_batch(pred, gt)
            acc.update(dist, ate_km=ate, cte_km=cte)
            n += 1
    r = acc.compute()
    r["ms_per_batch"] = (time.perf_counter() - t0) * 1e3 / max(n, 1)
    return r


def evaluate_full(model, loader, device, pred_len: int,
                   metrics_csv: str, epoch: int,
                   tag: str = "RAW", ema_obj=None) -> dict:
    backup = None
    if ema_obj is not None:
        try: backup = ema_obj.apply_to(model)
        except Exception as e:
            print(f"  ŌÜĀ  EMA apply failed: {e}")
            backup = None; ema_obj = None

    model.eval()
    acc = StepErrorAccumulator(pred_len)
    t0 = time.perf_counter(); n = 0
    with torch.no_grad():
        for batch in loader:
            bl   = move(list(batch), device)
            pred, _, _ = model.sample(bl, num_ensemble=1, ddim_steps=1)
            gt   = bl[1][:pred.shape[0]]
            dist, ate, cte = _eval_batch(pred, gt)
            acc.update(dist, ate_km=ate, cte_km=cte)
            n += 1

    r = acc.compute(); elapsed = time.perf_counter() - t0
    score = _composite_score(r)

    def _v(k): return r.get(k, float("nan"))
    def _m(v, t): return "Ō£ģ" if np.isfinite(v) and v < t else "ŌØī"

    print(f"\n{'='*68}")
    print(f"  [{tag} ep={epoch}  {elapsed:.0f}s  {n} batches]")
    print(f"  ADE={_v('ADE'):.1f}{_m(_v('ADE'),TARGETS['ADE'])}  "
          f"12h={_v('12h'):.0f}{_m(_v('12h'),TARGETS['12h'])}  "
          f"24h={_v('24h'):.0f}{_m(_v('24h'),TARGETS['24h'])}  "
          f"48h={_v('48h'):.0f}{_m(_v('48h'),TARGETS['48h'])}  "
          f"72h={_v('72h'):.0f}{_m(_v('72h'),TARGETS['72h'])}")
    if np.isfinite(_v("ATE_mean")):
        print(f"  ATE={_v('ATE_mean'):.1f}{_m(_v('ATE_mean'),TARGETS['ATE'])}  "
              f"CTE={_v('CTE_mean'):.1f}{_m(_v('CTE_mean'),TARGETS['CTE'])}")
    print(f"  vs ST-Trans: {_gap_vs_sttrans(r)}")
    beat = _beat_report(r)
    if beat: print(f"  {beat}")
    print(f"  Score={score:.2f}")
    print(f"{'='*68}\n")

    from datetime import datetime as _dt
    dm = DatasetMetrics(
        ade=_v("ADE") if np.isfinite(_v("ADE")) else 0.0,
        fde=_v("FDE") if np.isfinite(_v("FDE")) else 0.0,
        ugde_12h=_v("12h") if np.isfinite(_v("12h")) else 0.0,
        ugde_24h=_v("24h") if np.isfinite(_v("24h")) else 0.0,
        ugde_48h=_v("48h") if np.isfinite(_v("48h")) else 0.0,
        ugde_72h=_v("72h") if np.isfinite(_v("72h")) else 0.0,
        ate_abs_mean=_v("ATE_mean") if np.isfinite(_v("ATE_mean")) else 0.0,
        cte_abs_mean=_v("CTE_mean") if np.isfinite(_v("CTE_mean")) else 0.0,
        n_total=r.get("n_samples", 0),
        timestamp=_dt.now().strftime("%Y%m%d_%H%M%S"),
    )
    save_metrics_csv(dm, metrics_csv, tag=f"val_{tag}_ep{epoch:03d}")

    if backup is not None:
        try: ema_obj.restore(model, backup)
        except Exception as e: print(f"  ŌÜĀ  EMA restore failed: {e}")
    return r


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  Best saver
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

class MultiplexedBestSaver:
    def __init__(self, patience: int = 35, tol: float = 0.0):
        self.patience = patience; self.tol = tol
        self.counter  = 0; self.early_stop = False
        self.best_score = self.best_ade = self.best_72h = \
            self.best_ate = self.best_cte = \
            self.best_48h = self.best_24h = self.best_12h = float("inf")
        self.best_raw_score = self.best_ema_score = self.best_fast_score = float("inf")

    def update_per_metric(self, r, model, out_dir, epoch, opt, sched, tl, vl):
        ade = r.get("ADE", float("inf"))
        h72 = r.get("72h", float("inf"))
        ate = r.get("ATE_mean", float("inf"))
        cte = r.get("CTE_mean", float("inf"))
        improved = False
        for v, attr, fname, extra in [
            (ade, "best_ade", "best_ade.pth", {"ade": ade}),
            (h72, "best_72h", "best_72h.pth", {"h72": h72}),
            (ate, "best_ate", "best_ate.pth", {"ate": ate}),
            (cte, "best_cte", "best_cte.pth", {"cte": cte}),
        ]:
            if v < getattr(self, attr):
                setattr(self, attr, v); improved = True
                _save_checkpoint(os.path.join(out_dir, fname),
                                  epoch, model, opt, sched, self, tl, vl, extra)
        for v, a in [(r.get("48h",float("inf")), "best_48h"),
                      (r.get("24h",float("inf")), "best_24h"),
                      (r.get("12h",float("inf")), "best_12h")]:
            if v < getattr(self, a): setattr(self, a, v); improved = True
        return improved

    def _save_track(self, score, attr, fname, r, model, out_dir,
                     epoch, opt, sched, tl, vl, label):
        if score < getattr(self, attr) - self.tol:
            setattr(self, attr, score)
            _save_checkpoint(os.path.join(out_dir, fname),
                              epoch, model, opt, sched, self, tl, vl,
                              {"score": score,
                               "ade": r.get("ADE", float("nan")),
                               "h72": r.get("72h", float("nan"))})
            print(f"  Ō£ģ Best {label} score={score:.2f}  "
                  f"ADE={r.get('ADE',float('nan')):.1f}  "
                  f"72h={r.get('72h',float('nan')):.0f}  (ep {epoch})")

    def update_raw(self, r, model, out_dir, epoch, opt, sched, tl, vl):
        self._save_track(_composite_score(r), "best_raw_score",
                          "best_raw.pth", r, model, out_dir,
                          epoch, opt, sched, tl, vl, "RAW")

    def update_ema(self, r, model, out_dir, epoch, opt, sched, tl, vl):
        self._save_track(_composite_score(r), "best_ema_score",
                          "best_ema.pth", r, model, out_dir,
                          epoch, opt, sched, tl, vl, "EMA")

    def update_fast(self, r, model, out_dir, epoch, opt, sched, tl, vl):
        self._save_track(_composite_score(r), "best_fast_score",
                          "best_fast.pth", r, model, out_dir,
                          epoch, opt, sched, tl, vl, "FAST")

    def update_composite(self, r, model, out_dir, epoch, opt, sched,
                          tl, vl, min_epochs: int = 25):
        score = _composite_score(r)
        ade   = r.get("ADE", float("inf"))
        h72   = r.get("72h", float("inf"))
        ate   = r.get("ATE_mean", float("inf"))
        cte   = r.get("CTE_mean", float("inf"))

        if score < self.best_score - self.tol:
            self.best_score = score; self.counter = 0
            _save_checkpoint(os.path.join(out_dir, "best_composite.pth"),
                              epoch, model, opt, sched, self, tl, vl,
                              {"composite": score, "ade": ade,
                               "h72": h72, "ate": ate, "cte": cte})
            print(f"  Ō£ģ Best COMPOSITE={score:.2f}  ADE={ade:.1f}  "
                  f"72h={h72:.0f}  ATE={ate:.1f}  CTE={cte:.1f}  (ep {epoch})")
        else:
            self.counter += 1
            print(f"  No improvement {self.counter}/{self.patience}"
                  f"  (best={self.best_score:.2f} cur={score:.2f})"
                  f"  72h={h72:.0f}Ōåō{self.best_72h:.0f}")

        if epoch >= min_epochs and self.counter >= self.patience:
            self.early_stop = True


