def save_metrics_table_csv(results, csv_path, model_name, split,
                            epoch=None, train_loss=None, val_loss=None):
    os.makedirs(os.path.dirname(os.path.abspath(csv_path)), exist_ok=True)
    ts = datetime.now().strftime("%Y%m%d%H%M%S")
    fields = ["timestamp","split","epoch","model_type","train_loss","val_loss",
              "ADE_km","12h_km","24h_km","48h_km","72h_km","ATE_abs","CTE_abs",
              "storm_id","n_seq","beat_ADE","beat_72h","beat_ATE","beat_CTE",
              "beat_12h","beat_24h","beat_48h","composite_score"]
    write_hdr = not os.path.exists(csv_path)
    with open(csv_path, "a", newline="") as fh:
        w = csv.DictWriter(fh, fieldnames=fields)
        if write_hdr: w.writeheader()
        for r in results:
            def _f(k): v=r.get(k,float("nan")); return f"{v:.2f}" if np.isfinite(v) else "nan"
            def _b(k): v=r.get(k,float("nan")); return "YES" if np.isfinite(v) and v < TARGETS.get(k,float("inf")) else "NO"
            score = _composite_score({"ADE": r.get("ADE",float("inf")),
                                       "72h": r.get("72h",float("inf")),
                                       "48h": r.get("48h",float("inf")),
                                       "24h": r.get("24h",float("inf")),
                                       "12h": r.get("12h",float("inf")),
                                       "ATE_mean": r.get("ATE",float("inf")),
                                       "CTE_mean": r.get("CTE",float("inf"))})
            w.writerow({
                "timestamp": ts, "split": split,
                "epoch": epoch if epoch is not None else "",
                "model_type": model_name,
                "train_loss": f"{train_loss:.4f}" if train_loss else "",
                "val_loss":   f"{val_loss:.4f}"   if val_loss   else "",
                "ADE_km": _f("ADE"), "12h_km": _f("12h"), "24h_km": _f("24h"),
                "48h_km": _f("48h"), "72h_km": _f("72h"),
                "ATE_abs": _f("ATE"), "CTE_abs": _f("CTE"),
                "storm_id": r.get("storm_id",""), "n_seq": r.get("n_seq",""),
                "beat_ADE": _b("ADE"), "beat_72h": _b("72h"),
                "beat_ATE": _b("ATE"), "beat_CTE": _b("CTE"),
                "beat_12h": _b("12h"), "beat_24h": _b("24h"), "beat_48h": _b("48h"),
                "composite_score": f"{score:.2f}",
            })


def _print_storm_table(results, model_name):
    print(f"\n{'='*108}")
    print(f"  Per-Storm  |  {model_name}")
    print(f"  {'Storm':<14} {'N':>5}  {'ADE':>8}  {'12h':>8}  {'24h':>8}  {'48h':>8}  {'72h':>8}  {'ATE':>8}  {'CTE':>8}")
    print(f"  {'-'*104}")

    def _v(r, k):
        v = r.get(k, float("nan")); t = TARGETS.get(k)
        s = f"{v:>7.1f}" if np.isfinite(v) else "    nan"
        if t and np.isfinite(v): s += "Ō£ģ" if v < t else "ŌØī"
        else: s += "  "
        return s

    for r in results:
        sid = r["storm_id"]
        if sid == "OVERALL":
            print(f"  {'ŌöĆ'*104}")
            pre = f"  {'­¤ōŖ OVERALL':<14}"
        else:
            pre = f"  ­¤īĆ {sid:<11}"
        print(f"{pre} {r['n_seq']:>5}  "
              f"{_v(r,'ADE')}  {_v(r,'12h')}  {_v(r,'24h')}  "
              f"{_v(r,'48h')}  {_v(r,'72h')}  {_v(r,'ATE')}  {_v(r,'CTE')}")

    overall = results[-1]
    beats = [f"{k}={overall.get(k,float('nan')):.1f}Ō£ģ"
             for k in ["ADE","12h","24h","48h","72h","ATE","CTE"]
             if np.isfinite(overall.get(k, float("nan")))
             and overall.get(k) < TARGETS.get(k, float("inf"))]
    if beats: print(f"  ­¤Åå BEAT: {' | '.join(beats)}")
    print(f"{'='*108}\n")


